import React from "react";

export default function ColorDisplay({ selectedColor, additionalInfo }) {
  return (
    <div className="color-display">
      {/* Left section for the selected color */}
      <div className="color-display-left">
        <div
          className="selected-color"
          style={{
            width: "80%",
            height: "80%",
            backgroundColor: selectedColor || "#FFFFFF", // Default to white
          }}
        ></div>
      </div>

      {/* Right section for additional information */}
      <div className="color-display-right">
        <p>{additionalInfo || "Additional Info"}</p>
      </div>
    </div>
  );
}
